/** UsptBsnsPblancApplyBhExmntDao.save */
insert into uspt_bsns_pblanc_apply_bh_exmnt
	(
		apply_id
		, bh_exmnt_iem_id
		, ceck_result_div_cd
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{applyId}
		, #{bhExmntIemId}
		, #{ceckResultDivCd}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)
	on conflict (apply_id, bh_exmnt_iem_id)
	do update
	set ceck_result_div_cd = #{ceckResultDivCd}
		, updater_id = #{updaterId}
		, updated_dt = #{updatedDt}
